solution: class Solution {
    private static final int MOD = 1_000_000_007;

    public int numberOfWays(int n, int x) {
        int maxBase = 1;
        while (Math.pow(maxBase, x) <= n) maxBase++;
        maxBase--;

        int[] bases = new int[maxBase];
        for (int i = 1; i <= maxBase; i++) {
            bases[i - 1] = (int) Math.pow(i, x);
        }

        int[] dp = new int[n + 1];
        dp[0] = 1;

        for (int base : bases) {
            for (int j = n; j >= base; j--) {
                dp[j] = (dp[j] + dp[j - base]) % MOD;
            }
        }
        return dp[n];
    }
}
